external_knowledge:
; Active observations refer to observations that are currently being considered or are valid ('is_active' = 1); 
; Active users refer to users who are currently registered or have not been deactivated ('is_active' = 1); 
; Active weeks refer to weeks that are currently being observed or are part of the observation period ('is_active' = 1).

sql:
SELECT density_type, description
FROM densities
WHERE is_active = 1;

SELECT COUNT(*) AS density_types_count
FROM densities
WHERE is_active = 1;

SELECT COUNT(*) AS total_pre_observations
FROM observations
WHERE category_id = (SELECT category_id FROM categories WHERE category_name = 'Pre');
